// src/App.js - OPTIMIZED VERSION
import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import BreadcrumbNav from './components/BreadcrumbNav';
import Footer from './components/Footer';
import Home from './pages/Home';
import Courses from './pages/Courses';
import CourseDetail from './pages/CourseDetail';
import Upload from './pages/Upload';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import NotFound from './pages/404';
import './App.css';
import About from './pages/About';
import { AuthProvider } from './contexts/AuthContext';
import Register from './pages/Register';
import SearchResults from './pages/SearchResults';

// ✅ HIERARCHICAL PAGES IMPORTS
import YearSelection from './pages/YearSelection';
import SemesterSelection from './pages/SemesterSelection';
import SubjectSelection from './pages/SubjectSelection';
import MaterialsPage from './pages/MaterialsPage';

// ✅ PROFILE RELATED PAGES
import Profile from './pages/Profile';
import Downloads from './pages/Downloads';
import History from './pages/History';

function App() {
  return (
    <Router>
      <AuthProvider>
        <div className="App" style={{ 
          display: 'flex', 
          flexDirection: 'column', 
          minHeight: '100vh',
          backgroundColor: '#f8fafc'
        }}>
          <Navbar />
          <BreadcrumbNav />

          <main style={{ 
            padding: '20px', 
            flex: 1,
            maxWidth: '1400px',
            margin: '0 auto',
            width: '100%'
          }}>
            <Routes>
              {/* 🌍 PUBLIC ROUTES */}
              <Route path="/" element={<Home />} />
              <Route path="/about" element={<About />} />
              <Route path="/search" element={<SearchResults />} />

              {/* 🔐 AUTH ROUTES */}
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />

              {/* 📚 COURSE RELATED ROUTES */}
              <Route path="/courses" element={<Courses />} />
              <Route path="/courses/:id" element={<CourseDetail />} />

              {/* 🗂️ HIERARCHICAL COURSE ROUTES - FIXED PATHS */}
              <Route path="/course/:courseId" element={<YearSelection />} />
              <Route path="/course/:courseId/year/:yearId" element={<SemesterSelection />} />
              <Route path="/course/:courseId/year/:yearId/semester/:semId" element={<SubjectSelection />} />
              <Route
                path="/course/:courseId/year/:yearId/semester/:semId/subject/:subjectId"
                element={<MaterialsPage />}
              />

              {/* 📤 UPLOAD ROUTE */}
              <Route path="/upload" element={<Upload />} />

              {/* 👤 USER PROFILE ROUTES (PROTECTED) */}
              <Route path="/dashboard" element={<Dashboard />} />
              <Route path="/profile" element={<Profile />} />
              <Route path="/downloads" element={<Downloads />} />
              <Route path="/history" element={<History />} />
              <Route path="/materials" element={<MaterialsPage />} />

              {/* 🚫 404 ROUTE - ALWAYS LAST */}
              <Route path="*" element={<NotFound />} />
            </Routes>
          </main>

          <Footer />
        </div>
      </AuthProvider>
    </Router>
  );
}

export default App;
